#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=1005;
int n,xx,yy,vis[N][N],vis2[N][N],dx[]={0,1,-1,0,0},dy[]={0,0,0,1,-1};
struct node
{
	int w,x,y;
	bool operator<(const node other) const
	{
		if(w!=other.w) return w>other.w;
		if(x!=other.x) return x>other.x;
		return y>other.y;
	}
};
int bfs()
{
	priority_queue<node> q;
	q.push(node{0,xx,yy});
	vis2[xx][yy]=1;
	while(!q.empty())
	{
		node t=q.top();
		int x=t.x,y=t.y,w=t.w;
		q.pop();
		if(x==0&&y==0) return w;
		for(int i=1;i<=4;i++)
		{
			int nx=x+dx[i],ny=y+dy[i];
			if(nx<0||nx>1001||ny<0||ny>1001||(vis2[nx][ny]==1)) continue;
			if(vis[nx][ny]) q.push(node{w+1,nx,ny});
			else q.push(node{w,nx,ny});
			vis2[nx][ny]=1;
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>xx>>yy;
	for(int i=1;i<=n;i++)
	{
		int x,y;
		cin>>x>>y;
		vis[x][y]=1;
	}
	cout<<bfs();
	return 0;
}
